var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"낙원, 황금나무 그리고 클리포트 게임. 자네가… 이 모든 걸 계획했군.","JPN":"このすべてを計画したのが……君なのかね？","ENG":"Did you plan all of this...?","TWN":"這一切……都是你計畫的嗎？"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DASH_ANAP_CA_TRUE","text":{"KOREA":"…맞아요. 당신 같은 분이라면 이미 눈치채고 계셨을 테죠.","JPN":"……そうです。あなたのような方なら、すでに気づいておられたでしょう。","ENG":"...Yes. Someone like you must have already realized.","TWN":"……對。若是像你這樣的人，應該早已察覺了吧。"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"언제부터인지, 감히 물어봐도 되겠나?","JPN":"いつからだったのか、聞いてもいいかね。","ENG":"May I ask when it began?","TWN":"我可以問你，是從什麼時候開始的嗎？"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DASH_ANAP_CA_TRUE","text":{"KOREA":"제가 가진 운명이, 제 선택이 아닌 누군가의 손으로 만들어졌다는 걸 알게 됐을 때부터요.","JPN":"私の運命が、自分の選択ではなく誰かの手によって作られたものだと知った時からです。","ENG":"From the moment I learned that the fate I was given had been shaped by someone else's hand, not my own choice.","TWN":"當我得知自己的命運並非出於我的選擇，而是被他人所創造的那一刻起。"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DASH_ANAP_CA_TRUE","text":{"KOREA":"크나큰 비극을 겪고, 세상을 증오하는 마왕이 되어, 그 말미에는 늑대에게 잡아먹혀 그 양분이 될 뿐인 운명…","JPN":"大きな悲劇を経験し、世界を憎む魔王になり、やがてはオオカミに食べられ養分になるだけの運命……","ENG":"To suffer a great tragedy, become a Demon Lord who hates the world, and in the end be devoured by the Wolf and become its nourishment...","TWN":"歷經巨大的悲劇、成為憎恨世界的魔王，最終被狼吞噬、成為其養分的命運……"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DASH_ANAP_CA_TRUE","text":{"KOREA":"그게 바로 제가 만들어진 <color=#ffd34c>이유</color>였죠.","JPN":"それが私が作られた<color=#ffd34c>理由</color>でした。","ENG":"That was the <color=#ffd34c>reason</color> I was created.","TWN":"那就是我被創造出來的<color=#ffd34c>理由</color>。"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 이 정도의 힘이라면... 탐미엘이 멋대로 정한 그 운명을 비틀기엔 부족함이 없겠어.","JPN":"だが、これだけの力があれば……タミエルが勝手に決めたその運命を十分捻じ曲げられる。","ENG":"But with power like this... it should be more than enough to twist the fate Tammiel arbitrarily assigned to you.","TWN":"但若擁有這樣的力量……足以扭曲塔米爾隨意決定的命運。"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇게 하는 것이 자네가 예언한 완전한 낙원의 의미일 테고.","JPN":"そうするのが君の予言した、完全なる楽園の意味するところなのか？","ENG":"Is that what you meant by the perfect Promised Land you foretold?","TWN":"你那麼做，就是你預言的完整樂園的意義嗎？"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DASH_ANAP_CA_TRUE","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DASH_ANAP_CA_TRUE","text":{"KOREA":"아뇨. 이 힘은 제 운명을 바꾸기 위한 것이 아녜요.","JPN":"いいえ、この力は私の運命を変えるためのものではありません。","ENG":"No. This power is not meant to change my fate.","TWN":"不，這股力量不是為了改變我的命運。"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DASH_ANAP_CA_TRUE","text":{"KOREA":"그자가 만들어낸, 모든 운명을 바꾸기 위한 힘이죠.","JPN":"あの者が作り出した、すべての運命を変えるための力です。","ENG":"It is power meant to change all the fates she created.","TWN":"而是為了改變那個傢伙創造的所有命運。"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"...쿨럭.","JPN":"……ゲホッ。","ENG":"*...Cough*","TWN":"……咳。"},"stage":{"bg":"ANAPILIS","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEEJISOO_SIX_OFFICE_NULL","text":{"KOREA":"......!","JPN":"……！","ENG":"...!","TWN":"……！"},"stage":{"bg":"ANAPILIS","slots":{"L":{"char_id":"LEEJISOO_SIX_OFFICE_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEEJISOO_SIX_OFFICE_NULL","text":{"KOREA":"대장! 정신이 드시나요?!","JPN":"隊長！　気がつきましたか！？","ENG":"Commander! Are you awake?!","TWN":"隊長！你醒了嗎？！"},"stage":{"bg":"ANAPILIS","slots":{"L":{"char_id":"LEEJISOO_SIX_OFFICE_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"어라?","JPN":"あれ？","ENG":"Huh?","TWN":"咦？"},"stage":{"bg":"ANAPILIS","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"...크리스?","JPN":"……クリス？","ENG":"...Chris?","TWN":"……克莉絲？"},"stage":{"bg":"ANAPILIS","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"...레아 씨. 어떻게 된 거죠? 저, 꼼짝없이 죽었다고 생각했는데.","JPN":"……レアさん。どういうことですか？　私、絶対死んだと思ったのに。","ENG":"...Leah. What happened? I was certain I had died.","TWN":"……蕾亞，發生什麼事了？我還以為自己已經死了。"},"stage":{"bg":"ANAPILIS","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"...그러게.","JPN":"……そうだね。","ENG":"...I know.","TWN":"……是啊。"},"stage":{"bg":"ANAPILIS","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"눈을 감는 순간까지 아팠는데, 지금은 아무런 고통도 남아있지 않아.","JPN":"目を閉じる瞬間まで痛かったのに、今は全然痛くない。","ENG":"It hurt right up until the moment I closed my eyes, but now there's no pain left at all.","TWN":"我在閉上眼的那一刻仍然感到痛楚，但現在卻沒有任何痛苦。"},"stage":{"bg":"ANAPILIS","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"지휘관, 보여? 함께 싸우다 죽은 전사자들이... 다시 멀쩡히 살아나고 있다고!","JPN":"指揮官、見えるか？　一緒に戦って戦死した者たちが……蘇っている！","ENG":"Commander, do you see this? The soldiers who died fighting with us... they're coming back to life completely unharmed!","TWN":"指揮官，你看到了嗎？那些與我們並肩作戰而死去的戰士們……又重新復活了！"},"stage":{"bg":"ANAPILIS","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"...그래.","JPN":"……ああ。","ENG":"...Yes.","TWN":"……嗯。"},"stage":{"bg":"ANAPILIS","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"실로 경이로운 광경이군.","JPN":"信じられない光景だ。","ENG":"It truly is a miraculous sight.","TWN":"這實在是令人驚嘆的景象。"},"stage":{"bg":"ANAPILIS","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_PRIDE"},"R":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"...마왕도 아니면서 사자들을 부활시키다니. 이런 건 들은 적도 없군요.","JPN":"……魔王でもない者が死者を蘇らせるなんて、こんなことは聞いたこともありません。","ENG":"...To revive the dead without even being a Demon Lord. I've never heard of anything like this.","TWN":"……即使不是魔王也能讓死者復活，我從未聽說過這種事。"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"가능성이란 건... 이런 것까지 할 수 있는 거야?","JPN":"可能性ってのは……こんなことまでできるの？","ENG":"Possibilities... can really do something like this?","TWN":"所謂的可能性……竟然連這種事都能做到嗎？"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"말 그대로 가능성이니까.","JPN":"文字通り、可能性だからね。","ENG":"They are possibilities, after all.","TWN":"正因為是可能性。"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만... 인과율을 거스르는 가능성은 세피로트 나무를 권한을 침범하는 것이지.","JPN":"だが……因果律に逆らう可能性はセフィロトを汚染させる。","ENG":"But possibilities that defy causality corrupt the Tree of Sephiroth.","TWN":"但是……違逆因果律的可能性，會污染生命樹。"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DASH_ANAP_CA_TRUE","text":{"KOREA":"그래요. 세피로트 나무의 주인인 그자가 이걸 가만히 두고보진 않겠죠.","JPN":"そう。セフィロトの主である彼女は黙認しないでしょうね。","ENG":"Yes. The one who rules the Tree of Sephiroth won't simply overlook this.","TWN":"沒錯。那傢伙身為生命樹的主人，不會坐視不管的。"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"설마, 자넨 처음부터?","JPN":"まさか君は最初から？","ENG":"Surely, from the very beginning you...?","TWN":"難道說，你從一開始就……？"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};